package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.mock;
import static org.mockito.Mockito.when;

import java.io.IOException;
import java.io.Reader;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testWithRecordSeparator() {
        // Given
        char recordSeparator = '\n';
        CSVFormat csvFormat = new CSVFormat(',', '"', null, null, null, false, true, "\r\n", null, null, false, false);

        // When
        CSVFormat result = csvFormat.withRecordSeparator(recordSeparator);

        // Then
        assertEquals(String.valueOf(recordSeparator), result.getRecordSeparator());
    }

    @Test
    public void testWithRecordSeparator_null() {
        // Given
        char recordSeparator = '\0';
        CSVFormat csvFormat = new CSVFormat(',', '"', null, null, null, false, true, "\r\n", null, null, false, false);

        // When
        CSVFormat result = csvFormat.withRecordSeparator(recordSeparator);

        // Then
        assertEquals(String.valueOf(recordSeparator), result.getRecordSeparator());
    }

    @Test
    public void testWithRecordSeparator_mockPrivateMethod() throws Exception {
        // Given
        char recordSeparator = '\n';
        CSVFormat csvFormat = mock(CSVFormat.class);
        when(csvFormat.withRecordSeparator(String.valueOf(recordSeparator))).thenCallRealMethod();

        // When
        CSVFormat result = csvFormat.withRecordSeparator(recordSeparator);

        // Then
        assertEquals(String.valueOf(recordSeparator), result.getRecordSeparator());
    }
}
